5	void ULFPTownWidget::NativeOnInitialized()
6	{
7		Super::NativeOnInitialized();
8	
9		if (Button_Shop) Button_Shop->OnClicked.AddDynamic(this, &ULFPTownWidget::OnShopClicked);
10		if (Button_EvolutionTower) Button_EvolutionTower->OnClicked.AddDynamic(this, &ULFPTownWidget::OnEvolutionTowerClicked);
11		if (Button_Teleport) Button_Teleport->OnClicked.AddDynamic(this, &ULFPTownWidget::OnTeleportClicked);
12		if (Button_QuestNPC) Button_QuestNPC->OnClicked.AddDynamic(this, &ULFPTownWidget::OnQuestNPCClicked);
13		if (Button_SkillNode) Button_SkillNode->OnClicked.AddDynamic(this, &ULFPTownWidget::OnSkillNodeClicked);
14		if (Button_Close) Button_Close->OnClicked.AddDynamic(this, &ULFPTownWidget::OnCloseClicked);
15	}
