18	ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
19	{
20		CameraOffset = FVector::ZeroVector;
21	
22		// 创建世界地图编辑器组件
23		WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
24	}
