26	void ALFPWorldMapPlayerController::BeginPlay()
27	{
28		Super::BeginPlay();
29	
30		// 设置输入模式
31		FInputModeGameAndUI InputMode;
32		InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
33		InputMode.SetHideCursorDuringCapture(false);
34		SetInputMode(InputMode);
35		bShowMouseCursor = true;
36	
37		// 设置 Enhanced Input
38		if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
39		{
40			if (DefaultInputMapping)
41			{
42				Subsystem->AddMappingContext(DefaultInputMapping, 0);
43			}
44		}
45	
46		// 场景切换淡入效果
47		if (PlayerCameraManager)
48		{
49			ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
50			float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
51			PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
52		}
53	
54		// 首帧跳过相机平滑插值
55		bSnapCameraNextFrame = true;
56	}
57	
58	void ALFPWorldMapPlayerController::Tick(float DeltaTime)
59	{
60		Super::Tick(DeltaTime);
61	
62		if (bIsDragging)
63		{
64			DragTime += DeltaTime;
65		}
66	
67		// 更新相机位置和旋转
68		// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
69		FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
70	
71		// 相机旋转：俯视角
72		FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
73	
74		// 平滑插值并设置
75		FRotator CurrentRotation = GetControlRotation();
76		if (bSnapCameraNextFrame)
77		{
78			SetControlRotation(TargetRotation);
79		}
80		else
81		{
82			SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
83		}
84	
85		// 通过 Pawn 控制相机位置（如果有 Pawn）
86		if (APawn* ControlledPawn = GetPawn())
87		{
88			if (bSnapCameraNextFrame)
89			{
90				// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
91				ControlledPawn->SetActorLocation(TargetLocation);
92				bSnapCameraNextFrame = false;
93			}
94			else
95			{
96				FVector CurrentLocation = ControlledPawn->GetActorLocation();
97				ControlledPawn->SetActorLocation(
98					FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
99				);
100			}
101		}
102	}
103	
104	void ALFPWorldMapPlayerController::SetupInputComponent()
105	{
106		Super::SetupInputComponent();
107	
108		if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
109		{
110			// 基础操作
111			EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
112			EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
113	
114			// 相机操作
115			EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
116			EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
117			EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
118			EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
119			EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
120	
121			// 编辑器切换
122			EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
123		}
124	}
125	
126	// ============== 输入处理 ==============
127	
128	void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
129	{
130		bIsDragging = false;
131		if (DragTime > DragThresholdTime)
132		{
133			DragTime = 0.f;
134			return;
135		}
136		DragTime = 0.f;
137	
138		// 编辑器模式优先处理
139		if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
140		{
141			// 射线检测点击的节点
142			FHitResult HitResult;
143			GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
144			ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
145	
146			ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
147	
148			switch (CurrentTool)
149			{
150			case ELFPWorldMapEditorTool::WMET_PlaceNode:
151				{
152					// 射线投射到 Z=0 平面获取世界坐标
153					FVector WorldOrigin, WorldDirection;
154					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
155					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
156					{
157						float T = -WorldOrigin.Z / WorldDirection.Z;
158						FVector HitPoint = WorldOrigin + WorldDirection * T;
159						WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
160					}
161				}
162				break;
163	
164			case ELFPWorldMapEditorTool::WMET_RemoveNode:
165				if (ClickedNode)
166				{
167					WorldMapEditorComponent->SelectNode(ClickedNode);
168					WorldMapEditorComponent->RemoveSelectedNode();
169				}
170				break;
171	
172			case ELFPWorldMapEditorTool::WMET_MoveNode:
173				if (ClickedNode)
174				{
175					WorldMapEditorComponent->SelectNode(ClickedNode);
176				}
177				else if (WorldMapEditorComponent->GetSelectedNode())
178				{
179					// 移动到点击位置
180					FVector WorldOrigin, WorldDirection;
181					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
182					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
183					{
184						float T = -WorldOrigin.Z / WorldDirection.Z;
185						FVector HitPoint = WorldOrigin + WorldDirection * T;
186						WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
187					}
188				}
189				break;
190	
191			case ELFPWorldMapEditorTool::WMET_ConnectEdge:
192				if (ClickedNode)
193				{
194					WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
195				}
196				break;
197	
198			case ELFPWorldMapEditorTool::WMET_RemoveEdge:
199				if (ClickedNode)
200				{
201					WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
202				}
203				break;
204	
205			case ELFPWorldMapEditorTool::WMET_SetNodeParams:
206				if (ClickedNode)
207				{
208					WorldMapEditorComponent->SelectNode(ClickedNode);
209					WorldMapEditorComponent->ApplyParamsToSelectedNode();
210				}
211				break;
212	
213			default:
214				break;
215			}
216			return;
217		}
218	
219		// 游戏模式：棋子移动中屏蔽点击
220		ALFPWorldMapManager* Manager = GetWorldMapManager();
221		if (Manager && Manager->IsPawnMoving()) return;
222	
223		// 游戏模式：点击节点移动或进入
224		FHitResult HitResult;
225		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
226		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
227	
228		if (ClickedNode)
229		{
230			if (!Manager || !Manager->GetPlayerState()) return;
231	
232			int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
233	
234			// 点击当前节点 → 进入节点
235			if (ClickedNode->NodeID == CurrentNodeID)
236			{
237				EnterNode(ClickedNode);
238				return;
239			}
240	
241			// 点击相邻可达节点 → 移动
242			TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
243			if (ReachableIDs.Contains(ClickedNode->NodeID))
244			{
245				MoveToNode(ClickedNode);
246			}
247			else
248			{
249				// 不可达，只选中
250				SelectNode(ClickedNode);
251			}
252		}
253	}
254	
255	void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
256	{
257		// 取消选中和可达高亮
258		ClearReachableHighlight();
259		if (SelectedNode)
260		{
261			SelectedNode->SetHighlighted(false);
262			SelectedNode = nullptr;
263		}
264	}
265	
266	void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
267	{
268		if (!WorldMapEditorComponent) return;
269	
270		WorldMapEditorComponent->ToggleEditorMode();
271	
272		if (WorldMapEditorComponent->IsEditorActive())
273		{
274			// 创建或显示编辑器 Widget
275			if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
276			{
277				WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
278				if (WorldMapEditorWidget)
279				{
280					WorldMapEditorWidget->AddToViewport();
281					WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
282				}
283			}
284			else if (WorldMapEditorWidget)
285			{
286				WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
287			}
288	
289			bShowMouseCursor = true;
290		}
291		else
292		{
293			// 隐藏编辑器 Widget
294			if (WorldMapEditorWidget)
295			{
296				WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
297			}
298		}
299	}
300	
301	// ============== 相机操作 ==============
302	
303	void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
304	{
305		FVector2D PanInput = Value.Get<FVector2D>();
306		CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
307	}
308	
309	void ALFPWorldMapPlayerController::OnCameraDragStarted(const FInputActionValue& Value)
310	{
311		bIsDragging = true;
312		DragTime = 0.f;
313		GetMousePosition(DragStartPosition.X, DragStartPosition.Y);
314	}
315	
316	void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
317	{
318		if (!bIsDragging) return;
319	
320		FVector2D CurrentMousePos;
321		GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
322		FVector2D Delta = CurrentMousePos - DragStartPosition;
323	
324		CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
325		DragStartPosition = CurrentMousePos;
326	}
327	
328	void ALFPWorldMapPlayerController::OnCameraDragCompleted(const FInputActionValue& Value)
329	{
330		bIsDragging = false;
331	}
332	
333	void ALFPWorldMapPlayerController::OnCameraZoom(const FInputActionValue& Value)
334	{
335		float ZoomDelta = Value.Get<float>();
336		CurrentZoom = FMath::Clamp(CurrentZoom - ZoomDelta * CameraZoomSpeed, MinZoomDistance, MaxZoomDistance);
337	
338		// 应用缩放到相机
339		if (APlayerCameraManager* CameraManager = PlayerCameraManager)
340		{
341			FVector CameraLocation = CameraManager->GetCameraLocation();
342			CameraLocation.Z = CurrentZoom;
343			CameraManager->SetManualCameraFade(0.f, FLinearColor::Black, false);
344		}
345	}
346	
347	// ============== 节点交互 ==============
348	
349	void ALFPWorldMapPlayerController::SelectNode(ALFPWorldMapNode* Node)
350	{
351		// 取消之前的选中
352		if (SelectedNode)
353		{
354			SelectedNode->SetHighlighted(false);
355		}
356	
357		SelectedNode = Node;
358	
359		if (SelectedNode)
360		{
361			SelectedNode->SetHighlighted(true);
362		}
363	}
364	
365	void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
366	{
367		if (!Node) return;
368	
369		ALFPWorldMapManager* Manager = GetWorldMapManager();
370		if (!Manager) return;
371	
372		// 棋子移动中不允许操作
373		if (Manager->IsPawnMoving()) return;
374	
375		ClearReachableHighlight();
376	
377		// 记录目标节点，移动完成后自动进入
378		PendingEnterNode = Node;
379	
380		// 绑定棋子移动完成回调
381		if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
382		{
383			MapPawn->OnMoveComplete.AddUniqueDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
384		}
385	
386		bool bMoved = Manager->MovePlayer(Node->NodeID);
387		if (!bMoved)
388		{
389			PendingEnterNode = nullptr;
390		}
391	}
392	
393	void ALFPWorldMapPlayerController::ShowReachableNodes()
394	{
395		ClearReachableHighlight();
396	
397		ALFPWorldMapManager* Manager = GetWorldMapManager();
398		if (!Manager || !Manager->GetPlayerState()) return;
399	
400		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
401		for (int32 NodeID : ReachableIDs)
402		{
403			if (ALFPWorldMapNode* Node = Manager->GetNode(NodeID))
404			{
405				Node->SetHighlighted(true);
406				ReachableNodes.Add(Node);
407			}
408		}
409	}
410	
