423	void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
424	{
425		if (!Node) return;
426	
427		UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
428	
429		switch (Node->NodeType)
430		{
431		case ELFPWorldNodeType::WNT_Battle:
432		case ELFPWorldNodeType::WNT_Boss:
433			EnterBattle(Node);
434			break;
435	
436		case ELFPWorldNodeType::WNT_Event:
437			// TODO: 触发事件系统
438			UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
439			break;
440	
441		case ELFPWorldNodeType::WNT_Shop:
442			OpenShop(Node, false);
443			break;
444	
445		case ELFPWorldNodeType::WNT_HireMarket:
446			OpenHireMarket(Node, false);
447			break;
448	
449		case ELFPWorldNodeType::WNT_Town:
450			OpenTown(Node);
451			break;
452	
453		case ELFPWorldNodeType::WNT_QuestNPC:
454			// TODO: 触发任务对话
455			UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
456			break;
457	
458		case ELFPWorldNodeType::WNT_SkillNode:
459			// TODO: 打开技能树 UI
460			UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
461			break;
462	
463		case ELFPWorldNodeType::WNT_EvolutionTower:
464			OpenEvolutionTower();
465			break;
466	
467		default:
468			break;
469		}
470	}
