591	void ALFPWorldMapManager::UpdateFog()
592	{
593		if (!PlayerState) return;
594	
595		// 获取视野范围内的节点
596		TSet<int32> VisibleNodes = GetNodesWithinGraphDistance(PlayerState->CurrentNodeID, FogVisionRange);
597	
598		// 添加到永久揭露集合
599		for (int32 NodeID : VisibleNodes)
600		{
601			PlayerState->RevealedNodeIDs.Add(NodeID);
602		}
603	
604		// 更新所有节点的视觉状态
605		for (auto& Pair : NodeMap)
606		{
607			if (!Pair.Value) continue;
608	
609			Pair.Value->bIsRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key);
610			Pair.Value->UpdateVisualState();
611		}
612	
613		// 更新边的可见性（两端都揭露才可见）
614		for (auto& Pair : EdgeMap)
615		{
616			if (!Pair.Value) continue;
617	
618			bool bBothRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key.X)
619				&& PlayerState->RevealedNodeIDs.Contains(Pair.Key.Y);
620			Pair.Value->SetActorHiddenInGame(!bBothRevealed);
621		}
622	}
