693	void ALFPWorldMapManager::OnPawnMoveComplete()
694	{
695		if (PendingMoveTargetNodeID >= 0)
696		{
697			int32 NodeID = PendingMoveTargetNodeID;
698			PendingMoveTargetNodeID = -1;
699			HandlePostMove(NodeID);
700		}
701	}
