703	void ALFPWorldMapManager::HandlePostMove(int32 TargetNodeID)
704	{
705		// 更新迷雾
706		UpdateFog();
707	
708		// 触发节点事件（首次进入未触发的节点）
709		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
710		if (TargetNode && !TargetNode->bHasBeenTriggered)
711		{
712			switch (TargetNode->NodeType)
713			{
714			case ELFPWorldNodeType::WNT_Battle:
715			case ELFPWorldNodeType::WNT_Event:
716			case ELFPWorldNodeType::WNT_Boss:
717				TargetNode->bHasBeenTriggered = true;
718				TargetNode->UpdateVisualState();
719				break;
720			default:
721				break;
722			}
723		}
724	
725		// 回合压力检查
726		if (PlayerState && PlayerState->IsPastPressureThreshold())
727		{
728			UE_LOG(LogTemp, Warning, TEXT("回合压力: 已超过 %d 回合阈值！当前 %d 回合"),
729				PlayerState->TurnPressureThreshold, PlayerState->CurrentTurn);
730		}
731	}
